247	func (c *Controller) upgradeAISuiteInCluster(clusterCode, namespace, name, chartVersion string, customValues []*aisuite.CustomValues) error {
248		// 升级逻辑和安装类似，区别在于不接受部分参数，并且调用UpgradeRelease接口
249		suiteRegistry, err := getSuiteRegistry(c.db)
250		if err != nil {
251			log.Errorf("failed to get suite registry: %v", err)
252			return fmt.Errorf("failed to get suite registry: %w", err)
253		}
254		registryHost := strings.TrimPrefix(suiteRegistry.Address, "https://")
255		registryHost = strings.TrimPrefix(registryHost, "http://")
256		repoChart := fmt.Sprintf("oci://%s/%s/%s", registryHost, suiteChartProject, name)
257		setValues := make(map[string]interface{})
258		req := &helm.InstallOrUpgradeReleaseRequest{
259			Wait:    wait,
260			Timeout: waitTimeout,
261		}
262		for _, cv := range customValues {
263			switch cv.Name {
264			case helmParamPrefix + "timeout":
265				waitTimeoutFloat, ok := cv.Value.(float64) // JSON numbers are unmarshaled into float64
266				if !ok {
267					return fmt.Errorf("invalid type for timeout value: expected int, got %T", cv.Value)
268				}
269				waitTimeout := util.ToInt(waitTimeoutFloat)
270				req.Timeout = time.Duration(waitTimeout) * time.Second
271			default:
272				expandDotKey(setValues, cv.Name, cv.Value)
273			}
274		}
275		req.Host = registryHost
276		req.UserName = suiteRegistry.User
277		req.Password = suiteRegistry.Password
278		req.Namespace = namespace
279		req.Name = name
280		req.RepoChart = repoChart
281		req.Version = chartVersion
282		req.Labels = map[string]string{"DeployedBy": "TAPAISuite"}
283		req.Values = setValues
284	
285		return c.apiserverGetter.UpgradeRelease(clusterCode, req)
286	}
